import{_ as i,N as o,o as t,a as r,e as l,i as d}from"./chunks/framework.DW6Cm6Mn.js";const h=JSON.parse('{"title":"Sobre o Vala","description":"Vala é uma linguagem de programação orientada a objetos com compilador embutido, que gera código C e usa o sistema de tipos GObject.","frontmatter":{"title":"Sobre o Vala","description":"Vala é uma linguagem de programação orientada a objetos com compilador embutido, que gera código C e usa o sistema de tipos GObject."},"headers":[],"relativePath":"pt_BR/about/index.md","filePath":"pt_BR/about/index.md"}'),s={name:"pt_BR/about/index.md"};function n(m,a,c,p,u,b){const e=o("PredefinedCtaStack");return t(),r("div",null,[a[0]||(a[0]=l('<h1 id="sobre-o-vala" tabindex="-1">Sobre o Vala <a class="header-anchor" href="#sobre-o-vala" aria-label="Permalink to &quot;Sobre o Vala&quot;">​</a></h1><h2 id="o-que-e-vala" tabindex="-1">O que é Vala? <a class="header-anchor" href="#o-que-e-vala" aria-label="Permalink to &quot;O que é Vala?&quot;">​</a></h2><p>Vala é uma linguagem de programação orientada a objetos com compilador embutido, que gera código C e usa o sistema de tipos GObject.</p><p>Vala suporta funcionalidades de linguagens de programação moderna, como:</p><ul><li>Interfaces</li><li>Propriedades</li><li>Sinais</li><li>Declaração Foreach</li><li>Expressões Lambda</li><li>Inferência de tipo para variáveis locais</li><li>Programação genérica</li><li>Tipos Non-null</li><li>Gerenciamento de memória assistido</li><li>Tratamento de exceção</li><li>Módulos (Plugins)</li></ul><h2 id="que-tipo-de-linguagem-e-vala" tabindex="-1">Que tipo de linguagem é Vala? <a class="header-anchor" href="#que-tipo-de-linguagem-e-vala" aria-label="Permalink to &quot;Que tipo de linguagem é Vala?&quot;">​</a></h2><h3 id="produtiva" tabindex="-1">Produtiva <a class="header-anchor" href="#produtiva" aria-label="Permalink to &quot;Produtiva&quot;">​</a></h3><p>Com Vala, você pode entrar em operação rapidamente, graças a funcionalidades convenientes como expressões lambda, tratamento de exceção, interfaces e programação genérica.</p><h3 id="performante" tabindex="-1">Performante <a class="header-anchor" href="#performante" aria-label="Permalink to &quot;Performante&quot;">​</a></h3><p>Código Vala compila para binários inteiramente nativos.</p><h3 id="estaticamente-tipada" tabindex="-1">Estaticamente-Tipada <a class="header-anchor" href="#estaticamente-tipada" aria-label="Permalink to &quot;Estaticamente-Tipada&quot;">​</a></h3><p>Vala te ajuda a escrever código de tipagem segura, sem verbosidade, graças à inferência de tipos.</p><h3 id="integrativo" tabindex="-1">Integrativo <a class="header-anchor" href="#integrativo" aria-label="Permalink to &quot;Integrativo&quot;">​</a></h3><p>Vala é projetada para permitir acesso a bibliotecas C existentes, especialmente bibliotecas baseadas em GObject, sem a necessidade de bindings em tempo de execução. Tudo o que é necessário para usar uma biblioteca com Vala é um arquivo API, contendo as declarações de classe e método na sintaxe Vala. Vala atualmente vem com bindings para GLib e GTK+ e muitos outros para a Plataforma GNOME.</p><p>Vala também pode ser utilizada para criar bibliotecas C.</p><h3 id="familiar" tabindex="-1">Familiar <a class="header-anchor" href="#familiar" aria-label="Permalink to &quot;Familiar&quot;">​</a></h3><p>A sintaxe de Vala é inspirada em C# e Java, de modo que se você já usou alguma delas, você se adaptará perfeitamente à escrita de código Vala.</p>',17)),d(e)])}const f=i(s,[["render",n]]);export{h as __pageData,f as default};
